#include<bits/stdc++.h>
using namespace std;
int x;
int main(){
    int n;
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>x;
        if(x<=10){
            cout<<"R\n";
        }else if(x<=20){
            cout<<"L\n";
        }else{
            cout<<x<<'\n';
        }
    }
    return 0;
}
